INSERT INTO public.option_definition (entity_type,category,feature_number,code,description) VALUES
('hardware','hardware_category','butt_hinges','Butt hinges','selectors: Size, weight, bearing, material, corner/radius, finish, quantity, fire/wind rating; pioneer: DOR-035 to DOR-040; FRM-018 to FRM-021; preps: 450, 500, 450HW, 500HW, special hinge codes'),
('hardware','hardware_category','continuous_hinges','Continuous hinges','selectors: Manufacturer series, length, mounting type, material, finish, door clearance, hand; pioneer: DOR-035/039; FRM-018; preps: CONH, CONN, CONU, CONHF'),
('hardware','hardware_category','electric_hinges_ept_loops','Electric hinges / EPT / loops','selectors: Wire count/gauge, connectors, voltage/current, size, hand, template; pioneer: DOR-049 to DOR-051; FRM-033/034; preps: ELH, PTP, CN4'),
('hardware','hardware_category','closers_and_arms','Closers and arms','selectors: Manufacturer, series, arm type, hold-open, mounting, handedness, cover finish, door size/rating; pioneer: DOR-041/042; FRM-022/023; preps: STD, PAC, SOH, MOH, COC, SCC; frame closer codes'),
('hardware','hardware_category','cylindrical_mortise_locks_and_deadbolts','Cylindrical/mortise locks and deadbolts','selectors: Lock type, function, backset, trim, cylinder/core, keyway, grade, finish, fire/wind approval; pioneer: DOR-026 to DOR-034; FRM-015 to FRM-017; preps: CYL, L, T, MST, CDL, MDL, ESTK and strike codes'),
('hardware','hardware_category','exit_devices','Exit devices','selectors: Device type, length, dogging, electrification, rating, hand, finish, trim compatibility; pioneer: DOR-026 to DOR-034; FRM-015/024; preps: RP/RPP, SVR/SVRP, CVR, MPAN/MPNP, RED'),
('hardware','hardware_category','exit_trim_pulls','Exit trim / pulls','selectors: Compatible device series, function, cylinder, lever/pull style, finish, hand; pioneer: DOR-026 to DOR-034; preps: DTRP, PP, FP or device-specific prep'),
('hardware','hardware_category','inactive_leaf_hardware','Inactive-leaf hardware','selectors: Type, length, top/bottom, automatic/manual, fire/wind rating, finish; pioneer: DOR-043/044; FRM-024 and reinforcement fields; preps: FB, AFB, AFSP, AFBT, SBR; FBM/AFBR/CVRS'),
('hardware','hardware_category','lite_kits_and_louvers','Lite kits and louvers','selectors: Cutout/visible size, glass type/thickness, rating, kit material/finish, loose/installed; pioneer: DOR-015 to DOR-025; panel fields; preps: Door kit/louver codes; avoid duplicate Pioneer kit charges'),
('hardware','hardware_category','weather_seals','Weather seals','selectors: Profile, material, finish, mounting, required length, fire/smoke/wind rating; pioneer: Door/frame dimensions and performance fields; preps: Door-bottom prep, astragal selection, frame reinforcement where needed'),
('hardware','hardware_category','thresholds','Thresholds','selectors: Profile, width/depth, height, ADA, length, undercut, stop notch/fabrication; pioneer: Opening width; DOR-047; pivot/undercut fields; preps: Threshold usually external; coordinates undercut and frame profile'),
('hardware','hardware_category','protection_accessories','Protection/accessories','selectors: Width, height, gauge, material, finish, mounting, cylinder holes; pioneer: Door size, hand, lock prep, elevation; preps: May require PP/FP/DTRP or special drilling'),
('hardware','hardware_category','keying','Keying','selectors: System, format, keyway, keyed-alike/master-key group, core status, keys/quantity; pioneer: HWR keying fields and project-level key schedule; preps: Can affect lock/trim/cylinder selections'),
('hardware','hardware_category','access_control','Access control','selectors: Device type, voltage, current, fail-safe/secure, monitoring, protocol, enclosure, compatible lock; pioneer: DOR-049 to DOR-055; FRM-032 to FRM-035; preps: ESTK, PTP, ELH, DPS, MAGS, conduit and operator reinforcement');